import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

interface IReturn {
  createOnboardingSurvey: (survey: Partial<OnboardingSurvey>, options?: object) => void;
  createOnboardingSurveyIsLoading: boolean;
}

type Params = {
  shouldShowToast?: boolean;
};

export const useCreateOnboardingSurvey = (
  { shouldShowToast = true }: Params = { shouldShowToast: true }
): IReturn => {
  const { t } = useTranslation('accounts');
  const { showToast } = useToast();

  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;

  const { refreshCache } = useCacheHelper(resourceKeys.onboardingSurveys);

  const { isLoading, mutate } = useMutation<
    OnboardingSurvey,
    { message: string },
    Partial<OnboardingSurvey>
  >(
    (body) => {
      return new ApiClient().post(`/onboarding_survey?accountId=${accountId}`, body);
    },
    {
      onError: ({ message }) => {
        if (shouldShowToast) {
          showToast({
            message,
            variant: 'error',
          });
        }
      },
      onSuccess: (data) => {
        if (shouldShowToast) {
          showToast({
            message: t('state.update.onSuccess'),
            variant: 'success',
          });
        }

        return refreshCache(data.id);
      },
    }
  );

  return { createOnboardingSurvey: mutate, createOnboardingSurveyIsLoading: isLoading };
};

