import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type MutationParams = {
  accountName: string;
  connectionId: string;
};

export const useApproveIncomingAccountConnection = () => {
  const { showToast } = useToast();
  const { refreshCache: refreshIncoming } = useCacheHelper(resourceKeys.incomingAccountConnections);
  const { refreshCache: refreshOutgoing } = useCacheHelper(resourceKeys.outgoingAccountConnections);
  const { currentAccount: { id: accountId } = {} } = useGetAccount();
  const { t } = useTranslation('settings', { keyPrefix: 'connectedAccounts.state' });

  const { isLoading, mutate } = useMutation(
    ({ connectionId }: MutationParams) => {
      if (!accountId) {
        throw new Error('an account id must exist to approve an account connection!');
      }

      return new ApiClient().patch<null, null>(
        `/incoming_account_connections/${connectionId}/approve?account_id=${accountId}`
      );
    },
    {
      onError: (_, { accountName }) => {
        showToast({
          message: t('approveFailure', { accountName }),
          variant: 'error',
        });
      },

      onSuccess: async (_, { accountName }) => {
        await Promise.all([refreshIncoming(''), refreshOutgoing('')]);
        showToast({
          message: t('approveSuccess', { accountName }),
          variant: 'success',
        });
      },
    }
  );

  return {
    approveIncomingAccountConnection: mutate,
    isApprovingIncomingAccountConnection: isLoading,
  };
};

