import { AccountConnection, OutgoingAccountConnectionRequest } from '@domain/connectedAccounts';
import { IErrorResponse } from '@domain/error';
import { ApiClient } from '@service/anedot/client';
import { useGetAccount } from '@state/accounts';
import { resourceKeys, useCacheHelper } from '@state/cacheHelper';
import { useToast } from '@ui/components/Toast';
import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useMutation } from 'react-query';

type Params = {
  existingOutgoingConnections?: AccountConnection[];
};

export const useCreateOutgoingAccountConnection = ({ existingOutgoingConnections }: Params) => {
  const { showToast } = useToast();
  const { refreshCache } = useCacheHelper(resourceKeys.outgoingAccountConnections);

  const { refreshCache: refreshIncomingConnections } = useCacheHelper(
    resourceKeys.incomingAccountConnections
  );

  const { refreshCache: refreshOutgoingConnections } = useCacheHelper(
    resourceKeys.outgoingAccountConnections
  );

  const { refreshCache: refreshIncomingFunds } = useCacheHelper(
    resourceKeys.actionPagesFundsIncoming
  );

  const { t } = useTranslation('settings', { keyPrefix: 'connectedAccounts.state' });
  const { currentAccount: { id: accountId } = {} } = useGetAccount();

  const { error, isLoading, mutate, reset, variables } = useMutation<
    AccountConnection,
    IErrorResponse,
    string
  >(
    (externalAccountId) => {
      if (!accountId) {
        throw new Error('accountId must exist to create a connection request');
      }
      return new ApiClient().post<OutgoingAccountConnectionRequest, AccountConnection>(
        '/outgoing_account_connections',
        { accountId, externalAccountId }
      );
    },
    {
      onError: () => {
        showToast({
          message: t('createRequestFailure'),
          variant: 'error',
        });
      },

      onSuccess: async ({ account, id }) => {
        await refreshCache(id);
        await refreshIncomingConnections();
        await refreshOutgoingConnections();
        await refreshIncomingFunds();

        await showToast({
          message: t('createRequestSuccess', { accountName: account.displayName }),
          variant: 'success',
        });
      },
    }
  );

  const outgoingAccountConnectionRequestError = useMemo<IErrorResponse | undefined>(() => {
    if (!error) {
      return undefined;
    }
    return {
      ...error,
      errors: error.errors?.map((err) => ({
        ...err,
        details: err.details.map((detail) => {
          if (!detail.match(/already exists/)) {
            return detail;
          }

          const id = variables;
          const connection = existingOutgoingConnections?.find((c) => c.account.id === id);
          if (!connection) {
            return detail;
          }

          return {
            approved: t('requestErrors.exists'),
            rejected: t('requestErrors.blocked'),
            requested: t('requestErrors.requested'),
          }[connection.status];
        }),
      })),
    };
  }, [error, existingOutgoingConnections, t, variables]);

  return {
    createOutgoingAccountConnectionRequest: mutate,
    isCreatingAccountConnectionRequest: isLoading,
    outgoingAccountConnectionRequestError,
    resetCreateOutgoingAccountConnectionRequest: reset,
  };
};

